labs.cli:
# DR-region vault (copy destination) in us-west-2
aws backup create-backup-vault --backup-vault-name dr-vault --region us-west-2

# Primary vault in us-east-1
aws backup create-backup-vault --backup-vault-name primary-vault --region us-east-1

# Create the plan with daily rule + cross-region copy
aws backup create-backup-plan --region us-east-1 --backup-plan '{
  "BackupPlanName": "daily-with-dr-copy",
  "Rules": [{
    "RuleName": "daily",
    "TargetBackupVaultName": "primary-vault",
    "ScheduleExpression": "cron(0 5 * * ? *)",
    "StartWindowMinutes": 60,
    "Lifecycle": {"DeleteAfterDays": 30},
    "CopyActions": [{
      "DestinationBackupVaultArn": "arn:aws:backup:us-west-2:111122223333:backup-vault:dr-vault",
      "Lifecycle": {"DeleteAfterDays": 30}
    }]
  }]
}'

# Assign resources tagged backup=daily (replace plan id from previous output)
aws backup create-backup-selection --region us-east-1 \
  --backup-plan-id <PLAN_ID> \
  --backup-selection '{
    "SelectionName": "tagged",
    "IamRoleArn": "arn:aws:iam::111122223333:role/service-role/AWSBackupDefaultServiceRole",
    "ListOfTags": [{"ConditionType":"STRINGEQUALS","ConditionKey":"backup","ConditionValue":"daily"}]
  }'
